// Validate registration form data
const body = $input.first().json.body || $input.first().json;

const errors = [];

// Required fields
const firstName = (body.first_name || '').trim();
const lastName = (body.last_name || '').trim();
const email = (body.email || '').trim().toLowerCase();
const company = (body.company || '').trim();
const eventId = (body.event_id || '').trim();
const sessionId = (body.session_id || '').trim();
const promoCode = (body.promo_code || '').trim();

if (!firstName) errors.push('first_name is required');
if (!lastName) errors.push('last_name is required');
if (!email) errors.push('email is required');
if (!company) errors.push('company is required');
if (!eventId) errors.push('event_id is required');

// Email format validation
const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
if (email && !emailRegex.test(email)) {
  errors.push('Invalid email format');
}

// Promo code is passed in from the form (e.g., SPEAKER20, EARLYBIRD, VIP50)

if (errors.length > 0) {
  return [{
    json: {
      valid: false,
      errors,
      statusCode: 400
    }
  }];
}

return [{
  json: {
    valid: true,
    first_name: firstName,
    last_name: lastName,
    email: email,
    company: company,
    event_id: eventId,
    session_id: sessionId,
    promo_code: promoCode,
    registered_at: new Date().toISOString()
  }
}];

// Merge original registration data with enrichment results
const validated = $('Validate Registration Data').first().json;
const hubspot = $('Create or Update HubSpot Contact').first().json;
const enrichment = $input.first().json || {};

return [{
  json: {
    first_name: validated.first_name,
    last_name: validated.last_name,
    email: validated.email,
    company: validated.company,
    event_id: validated.event_id,
    promo_code: validated.promo_code || '',
    registered_at: validated.registered_at,
    hubspot_contact_id: hubspot.id || hubspot.vid || '',
    enrichment: {
      company_size: enrichment.company_size || '',
      industry: enrichment.industry || '',
      role: enrichment.role || '',
      seniority: enrichment.seniority || '',
      linkedin_url: enrichment.linkedin_url || '',
      location: enrichment.location || '',
      company_domain: enrichment.company_domain || '',
      enrichment_score: enrichment.enrichment_score || 0,
      enrichment_sources: enrichment.enrichment_sources || []
    }
  }
}];

