parameters.jsCode:
// Log promo code usage for analytics
const promoCode = $json.promo_code;

return [{
  json: {
    promo_code: promoCode,
    used_by: $json.email,
    event_id: $json.event_id,
    used_at: new Date().toISOString()
  }
}];

// Prepare analytics row for the registration event
const reg = $json;
const enrichment = reg.enrichment || {};

return [{
  json: {
    event_id: reg.event_id,
    email: reg.email,
    company: reg.company,
    industry: enrichment.industry || '',
    company_size: enrichment.company_size || '',
    enrichment_score: enrichment.enrichment_score || 0,
    enrichment_sources: (enrichment.enrichment_sources || []).join(', '),
    promo_code: reg.promo_code || '',
    registered_at: reg.registered_at,
    source: 'direct_registration'
  }
}];

// Initialize enrichment state from registration data
const hubspot = $('Create or Update HubSpot Contact').first().json;
const validated = $('Validate Registration Data').first().json;

return [{
  json: {
    // Input fields — prefer validated data, HubSpot as fallback
    email: validated.email || hubspot.properties?.email || '',
    first_name: validated.first_name || hubspot.properties?.firstname || '',
    last_name: validated.last_name || hubspot.properties?.lastname || '',
    company: validated.company || hubspot.properties?.company || '',
    event_id: validated.event_id || '',

    // Enrichment fields (to be filled by waterfall)
    company_size: '',
    industry: '',
    role: '',
    seniority: '',
    linkedin_url: '',
    location: '',
    company_domain: '',
    company_description: '',
    person_bio: '',

    // Meta
    enrichment_sources: [],
    enrichment_score: 0,
    started_at: new Date().toISOString()
  }
}];

// Return the cached enriched profile
const cached = $input.first().json;
return [{
  json: {
    ...cached,
    enrichment_sources: ['cache'],
    from_cache: true
  }
}];

// Parse Clearbit combined API response
const state = $('Initialize Enrichment State').first().json;
const result = $input.first().json;

// Check if Clearbit returned useful data
const person = result.person || {};
const company = result.company || {};

let enriched = { ...state };
let sources = [...(state.enrichment_sources || [])];

if (person.employment?.title) {
  enriched.role = person.employment.title;
  enriched.seniority = person.employment.seniority || '';
  sources.push('clearbit_person');
}

if (person.linkedin?.handle) {
  enriched.linkedin_url = 'https://linkedin.com/in/' + person.linkedin.handle;
}

if (person.location) {
  enriched.location = person.location;
}

if (person.bio) {
  enriched.person_bio = person.bio;
}

if (company.name) {
  enriched.company_domain = company.domain || '';
  enriched.company_description = company.description || '';
  sources.push('clearbit_company');
}

if (company.metrics?.employees) {
  const emp = company.metrics.employees;
  if (emp < 50) enriched.company_size = 'startup';
  else if (emp < 200) enriched.company_size = 'SMB';
  else if (emp < 1000) enriched.company_size = 'mid-market';
  else enriched.company_size = 'enterprise';
}

if (company.category?.industry) {
  enriched.industry = company.category.industry;
}

enriched.enrichment_sources = sources;

return [{ json: enriched }];

// Parse Proxycurl LinkedIn resolution response
const state = $('Parse Clearbit Results').first().json;
const result = $input.first().json;

let enriched = { ...state };
let sources = [...(enriched.enrichment_sources || [])];

if (result.url || result.linkedin_profile_url) {
  enriched.linkedin_url = enriched.linkedin_url || result.url || result.linkedin_profile_url || '';
  sources.push('proxycurl');
}

if (result.headline) {
  enriched.role = enriched.role || result.headline;
}

if (result.industry) {
  enriched.industry = enriched.industry || result.industry;
}

if (result.city || result.country_full_name) {
  enriched.location = enriched.location || [result.city, result.country_full_name].filter(Boolean).join(', ');
}

if (result.summary) {
  enriched.person_bio = enriched.person_bio || result.summary;
}

enriched.enrichment_sources = sources;

return [{ json: enriched }];

// Merge AI extraction results with existing enrichment state
const state = $('Parse Proxycurl Results').first()?.json
  || $('Parse Clearbit Results').first()?.json
  || $('Initialize Enrichment State').first().json;

const aiResult = $input.first().json.output || $input.first().json || {};

let enriched = { ...state };
let sources = [...(enriched.enrichment_sources || [])];

// Only fill in missing fields from AI extraction
if (!enriched.role && aiResult.role) enriched.role = aiResult.role;
if (!enriched.industry && aiResult.industry) enriched.industry = aiResult.industry;
if (!enriched.location && aiResult.location) enriched.location = aiResult.location;
if (!enriched.linkedin_url && aiResult.linkedin_url) enriched.linkedin_url = aiResult.linkedin_url;
if (!enriched.company_size && aiResult.company_size) enriched.company_size = aiResult.company_size;
if (!enriched.seniority && aiResult.seniority) enriched.seniority = aiResult.seniority;

if (aiResult.role || aiResult.industry || aiResult.location) {
  sources.push('google_ai');
}

enriched.enrichment_sources = sources;

return [{ json: enriched }];

// Score enrichment completeness (0-100)
const d = $input.first().json;

let score = 0;
const weights = {
  role: 20,
  industry: 15,
  company_size: 15,
  linkedin_url: 15,
  location: 10,
  seniority: 10,
  company_domain: 5,
  person_bio: 5,
  company_description: 5
};

for (const [field, weight] of Object.entries(weights)) {
  if (d[field] && d[field].trim() !== '') {
    score += weight;
  }
}

return [{
  json: {
    ...d,
    enrichment_score: score,
    completed_at: new Date().toISOString()
  }
}];

// Parse and validate promo/discount code
const body = $input.first().json.body || $input.first().json;
const promoCode = (body.promo_code || body.code || '').trim().toUpperCase();

if (!promoCode) {
  return [{
    json: {
      valid: false,
      message: 'No promo code provided',
      discount_percent: 0
    }
  }];
}

return [{
  json: {
    valid: true,
    promo_code: promoCode,
    checked_at: new Date().toISOString()
  }
}];

// Validate promo code against lookup results
const result = $input.first().json;
const rows = result.data || result.rows || [result];
const promoCode = $('Parse Promo Code').first().json.promo_code;

// Check if promo code exists and is still valid
const match = rows.find(r =>
  (r.code || '').toUpperCase() === promoCode
);

if (!match) {
  return [{
    json: {
      valid: false,
      promo_code: promoCode,
      message: 'Invalid promo code',
      discount_percent: 0
    }
  }];
}

// Check expiry
const expiresAt = match.expires_at ? new Date(match.expires_at) : null;
if (expiresAt && expiresAt < new Date()) {
  return [{
    json: {
      valid: false,
      promo_code: promoCode,
      message: 'This promo code has expired',
      discount_percent: 0
    }
  }];
}

// Check usage limit
const maxUses = parseInt(match.max_uses || '0', 10);
const currentUses = parseInt(match.current_uses || '0', 10);
if (maxUses > 0 && currentUses >= maxUses) {
  return [{
    json: {
      valid: false,
      promo_code: promoCode,
      message: 'This promo code has reached its usage limit',
      discount_percent: 0
    }
  }];
}

return [{
  json: {
    valid: true,
    promo_code: promoCode,
    discount_percent: parseInt(match.discount_percent || '0', 10),
    discount_label: match.label || promoCode,
    message: match.label || ('Discount: ' + match.discount_percent + '% off'),
    current_uses: currentUses + 1
  }
}];
